sql:
SELECT SUM(value) AS total_value
FROM asset_values
WHERE quarter_id = 1;

SELECT description
FROM financial_assets
WHERE company_id = 1;

SELECT COUNT(*) AS asset_count
FROM financial_assets
WHERE company_id = 1;

SELECT company_name
FROM financial_companies
WHERE company_id = 1;

SELECT asset_id, MAX(change_date) AS latest_change_date
FROM audit_trails
GROUP BY asset_id;

SELECT MAX(value) AS peak_worth
FROM asset_values
WHERE asset_id = 1;

external_knowledge:
- Top 3 financial assets imply those with the highest values; 
- The ranking is done separately for each quarter of each year. 
- Financial assets are ranked based on their value in descending order.

sql:
SELECT year_name
FROM years
ORDER BY year_name ASC;

SELECT value
FROM asset_values
WHERE asset_id = 1 AND quarter_id = 1;

SELECT quarter_id, COUNT(value_id) AS value_count
FROM asset_values
GROUP BY quarter_id;
